eturn value, post-effect, is the value of their prefered setting\n */\nexport const useReducedMotion = () => {\n  const [reducedMotion, setReducedMotion] = useState<boolean | null>(null)\n\n  useIsomorphicLayoutEffect(() => {\n    const mql = window.matchMedia('(prefers-reduced-motion)')\n\n    const handleMediaChange = (e: MediaQueryListEvent | MediaQueryList) => {\n      setReducedMotion(e.matches)\n\n      assign({\n        skipAnimation: e.matches,\n      })\n    }\n\n    handleMediaChange(mql)\n\n    if (mql.addEventListener) {\n      mql.addEventListener('change', handleMediaChange)\n    } else {\n      mql.addListener(handleMediaChange)\n    }\n\n    return () => {\n      if (mql.removeEventListener) {\n        mql.removeEventListener('change', handleMediaChange)\n      } else {\n        mql.removeListener(handleMediaChange)\n      }\n    }\n  }, [])\n\n  return reducedMotion\n}\n"],"mappings":";;;;;;;;;;;;;;;;;;;;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA,gBAAAA;AAAA,EAAA;AAAA,kCAAAC;AAAA,EAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;;;ACAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA,kBAA0B;;;ACGnB,SAAS,OAAO;AAAC;AAEjB,IAAM,eAAe,CAAC,KAAU,KAAU,UAC/C,OAAO,eAAe,KAAK,KAAK,EAAE,OAAO,UAAU,MAAM,cAAc,KAAK,CAAC;AAOxE,IAAM,KAAK;AAAA,EAChB,KAAK,MAAM;AAAA,EACX,KAAK,CAAI,MACP,CAAC,CAAC,KAAK,EAAE,YAAY,SAAS;AAAA,EAChC,KAAM,CAAC,MAAe,OAAO,MAAM;AAAA,EACnC,KAAK,CAAC,MAA4B,OAAO,MAAM;AAAA,EAC/C,KAAK,CAAC,MAA4B,OAAO,MAAM;AAAA,EAC/C,KAAK,CAAC,MAA+B,MAAM;AAC7C;AAGO,SAAS,QAAQ,GAAQ,GAAQ;AACtC,MAAI,GAAG,IAAI,CAAC,GAAG;AACb,QAAI,CAAC,GAAG,IAAI,CAAC,KAAK,EAAE,WAAW,EAAE;AAAQ,aAAO;AAChD,aAAS,IAAI,GAAG,IAAI,EAAE,QAAQ,KAAK;AACjC,UAAI,EAAE,CAAC,MAAM,EAAE,CAAC;AAAG,eAAO;AAAA,IAC5B;AACA,WAAO;AAAA,EACT;AACA,SAAO,MAAM;AACf;AAQO,IAAM,OAAO,CAClB,KACA,OACG,IAAI,QAAQ,EAAE;AAGZ,SAAS,SACd,KACA,IAKA,KACA;AACA,MAAI,GAAG,IAAI,GAAG,GA